require_once dirname(__DIR__) . '/includes/cms.php';$pdo=obtenerConexion();$id=cmsId($_GET['id']??$_POST['id']??0);$f=['id'=>0,'texto'=>'','url'=>'','orden'=>0,'activo'=>1,'nueva_pestana'=>0];if($id){$q=$pdo->prepare('SELECT * FROM menu_sitio WHERE id=:id');$q->execute(['id'=>$id]);$f=$q->fetch()?:$f;}$errores=[];
if($_SERVER['REQUEST_METHOD']==='POST'){if(!validarTokenCsrf($_POST['csrf_token']??null))$errores[]='Token CSRF inválido.';$texto=trim((string)($_POST['texto']??''));$url=trim((string)($_POST['url']??''));$orden=(int)($_POST['orden']??0);$activo=isset($_POST['activo'])?1:0;$nueva=isset($_POST['nueva_pestana'])?1:0;if($texto===''||mb_strlen($texto)>100)$errores[]='El texto es obligatorio.';if($url===''||!cmsUrlValida($url))$errores[]='La URL no es segura o válida.';if(!$errores){$datos=['texto'=>$texto,'url'=>$url,'orden'=>$orden,'activo'=>$activo,'nueva'=>$nueva];if($id){$datos['id']=$id;$q=$pdo->prepare('UPDATE menu_sitio SET texto=:texto,url=:url,orden=:orden,activo=:activo,nueva_pestana=:nueva WHERE id=:id');}else$q=$pdo->prepare('INSERT INTO menu_sitio(texto,url,orden,activo,nueva_pestana) VALUES(:texto,:url,:orden,:activo,:nueva)');$q->execute($datos);cmsFlash('exito','Enlace guardado.');header('Location: index.php');exit;}$f=array_merge($f,['texto'=>$texto,'url'=>$url,'orden'=>$orden,'activo'=>$activo,'nueva_pestana'=>$nueva]);}
cmsCabecera($id?'Editar enlace':'Agregar enlace','navbar/index.php');?><?php foreach($errores as $e):?><div class="alert alert-danger"><?=atenea_e($e)?></div><?php endforeach;?><form method="post" class="card card-rounded"><div class="card-header bg-white"><h2 class="card-title mb-1">Datos del enlace</h2><p class="text-muted mb-0">Texto y URL son obligatorios.</p></div><div class="card-body row g-3"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="id" value="<?=$id?>"><div class="col-md-6"><label class="form-label">Texto</label><input class="form-control" name="texto" maxlength="100" value="<?=atenea_e($f['texto'])?>" required></div><div class="col-md-6"><label class="form-label">URL</label><input class="form-control" name="url" maxlength="500" value="<?=atenea_e($f['url'])?>" required></div><div class="col-md-4"><label class="form-label">Orden</label><input class="form-control" type="number" name="orden" value="<?=(int)$f['orden']?>"></div><div class="col-md-4 d-flex align-items-end"><div class="form-check form-switch mb-2"><input class="form-check-input" type="checkbox" name="activo" <?=$f['activo']?'checked':''?>><label>Activo</label></div></div><div class="col-md-4 d-flex align-items-end"><div class="form-check form-switch mb-2"><input class="form-check-input" type="checkbox" name="nueva_pestana" <?=$f['nueva_pestana']?'checked':''?>><label>Nueva pestaña</label></div></div><div class="col-12"><a class="btn btn-light" href="index.php"><i class="mdi mdi-arrow-left me-1"></i>Volver</a> <a class="btn btn-outline-secondary" href="index.php">Cancelar</a> <button class="btn btn-primary text-white"><i class="mdi mdi-content-save me-1"></i>Guardar cambios</button></div></div></form><?php cmsPie();?>
